```typescript
export type FarmState =
  | { status: "none" }
  | { status: "operating"; id: string; owner: string; activeCrops: number }
  | { status: "decommissioned"; id: string; closedAt: string };

export type FarmCommand =
  | { type: "register"; id: string; owner: string }
  | { type: "startCrop" }
  | { type: "endCrop" }
  | { type: "decommission"; at: string };

export type FarmEvent =
  | { type: "FarmRegistered"; id: string; owner: string }
  | { type: "FarmCropStarted" }
  | { type: "FarmCropEnded" }
  | { type: "FarmDecommissioned"; at: string };

export class DomainError extends Error {
  constructor(public readonly code: string) {
    super(code);
    this.name = "DomainError";
  }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const farmDecider: Decider<FarmCommand, FarmEvent, FarmState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "register":
        if (state.status !== "none") throw new DomainError("FARM_EXISTS");
        return [{ type: "FarmRegistered", id: command.id, owner: command.owner }];
      case "startCrop":
        if (state.status !== "operating") throw new DomainError("NOT_OPERATING");
        return [{ type: "FarmCropStarted" }];
      case "endCrop":
        if (state.status !== "operating" || state.activeCrops === 0)
          throw new DomainError("NO_ACTIVE_CROPS");
        return [{ type: "FarmCropEnded" }];
      case "decommission":
        if (state.status !== "operating") throw new DomainError("NOT_OPERATING");
        if (state.activeCrops > 0) throw new DomainError("HAS_ACTIVE_CROPS");
        return [{ type: "FarmDecommissioned", at: command.at }];
      default: {
        const _n: never = command;
        throw new DomainError("UNKNOWN_COMMAND");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "FarmRegistered":
        return { status: "operating", id: event.id, owner: event.owner, activeCrops: 0 };
      case "FarmCropStarted":
        if (state.status !== "operating") return state;
        return { ...state, activeCrops: state.activeCrops + 1 };
      case "FarmCropEnded":
        if (state.status !== "operating") return state;
        return { ...state, activeCrops: Math.max(0, state.activeCrops - 1) };
      case "FarmDecommissioned":
        if (state.status !== "operating") return state;
        return { status: "decommissioned", id: state.id, closedAt: event.at };
      default: {
        const _n: never = event;
        return state;
      }
    }
  },
};
