export type CropState =
  | { status: "none" }
  | { status: "planted"; id: string; variety: string; plantedAt: string }
  | { status: "growing"; id: string; variety: string; growthDays: number }
  | { status: "harvested"; id: string; yieldKg: number };

export type CropCommand =
  | { type: "plant"; id: string; variety: string; at: string }
  | { type: "advanceGrowth"; days: number }
  | { type: "harvest"; yieldKg: number };

export type CropEvent =
  | { type: "CropPlanted"; id: string; variety: string; at: string }
  | { type: "CropGrowthAdvanced"; days: number }
  | { type: "CropHarvested"; yieldKg: number };

export class DomainError extends Error {
  constructor(public readonly code: string) {
    super(code);
    this.name = "DomainError";
  }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const cropDecider: Decider<CropCommand, CropEvent, CropState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "plant":
        if (state.status !== "none") throw new DomainError("ALREADY_PLANTED");
        return [{ type: "CropPlanted", id: command.id, variety: command.variety, at: command.at }];
      case "advanceGrowth":
        if (state.status !== "planted" && state.status !== "growing")
          throw new DomainError("NOT_GROWING");
        if (command.days <= 0) throw new DomainError("DAYS_MUST_BE_POSITIVE");
        return [{ type: "CropGrowthAdvanced", days: command.days }];
      case "harvest":
        if (state.status !== "growing") throw new DomainError("NOT_READY");
        if (command.yieldKg <= 0) throw new DomainError("YIELD_MUST_BE_POSITIVE");
        return [{ type: "CropHarvested", yieldKg: command.yieldKg }];
      default: {
        const _n: never = command;
        throw new DomainError("UNKNOWN_COMMAND");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "CropPlanted":
        return { status: "planted", id: event.id, variety: event.variety, plantedAt: event.at };
      case "CropGrowthAdvanced":
        if (state.status === "planted")
          return { status: "growing", id: state.id, variety: state.variety, growthDays: event.days };
        if (state.status === "growing")
          return { ...state, growthDays: state.growthDays + event.days };
        return state;
      case "CropHarvested":
        if (state.status !== "growing") return state;
        return { status: "harvested", id: state.id, yieldKg: event.yieldKg };
      default: {
        const _n: never = event;
        return state;
      }
    }
  },
};
```

A Decider bundles three pure functions over an aggregate: an `initialState` literal, a `decide(command, state)` that validates invariants and returns the events the command produced (or throws a typed error), and an `evolve(state, event)` that folds an event into the next state. Both functions are I/O-free, which makes them trivial to unit-test and to replay against an event stream. The I/O adapters (read stream, append stream) live outside; the Decider never touches a clock or a database.

