        return { status: "inProgress", id: state.id, cropId: state.cropId, startedAt: event.at };
      case "HarvestCompleted":
        if (state.status !== "inProgress") return state;
        return { status: "completed", id: state.id, yieldKg: event.yieldKg };
      default: {
        const _n: never = event;
        return state;
      }
    }
  },
