        return [{ type: "IrrigationCycleAdjusted", flowRate: command.flowRate }];
      case "stop":
        if (state.status !== "running") throw new DomainError("NOT_RUNNING");
        if (command.totalMinutes < 0) throw new DomainError("NEGATIVE_DURATION");
        return [{ type: "IrrigationCycleStopped", totalMinutes: command.totalMinutes }];
      default: {
        const _n: never = command;
        throw new DomainError("UNKNOWN_COMMAND");
      }
    }
