    switch (event.type) {
      case "IrrigationCycleStarted":
        return { status: "running", id: event.id, zone: event.zone, flowRate: event.flowRate, startedAt: event.at };
      case "IrrigationCycleAdjusted":
        if (state.status !== "running") return state;
        return { ...state, flowRate: event.flowRate };
