  | { type: "addAnimals"; count: number }
  | { type: "removeAnimals"; count: number }
  | { type: "retire"; at: string };

export type LivestockHerdEvent =
  | { type: "LivestockHerdRegistered"; id: string; species: string }
  | { type: "LivestockHerdAnimalsAdded"; count: number }
  | { type: "LivestockHerdAnimalsRemoved"; count: number }
  | { type: "LivestockHerdRetired"; at: string };

