  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "register":
        if (state.status !== "none") throw new DomainError("HERD_EXISTS");
        return [{ type: "LivestockHerdRegistered", id: command.id, species: command.species }];
