        if (state.status !== "active") throw new DomainError("NOT_ACTIVE");
        if (command.count <= 0) throw new DomainError("COUNT_MUST_BE_POSITIVE");
        return [{ type: "LivestockHerdAnimalsAdded", count: command.count }];
