        if (command.count > state.headCount) throw new DomainError("INSUFFICIENT_HEAD_COUNT");
        return [{ type: "LivestockHerdAnimalsRemoved", count: command.count }];
      case "retire":
        if (state.status !== "active") throw new DomainError("NOT_ACTIVE");
        return [{ type: "LivestockHerdRetired", at: command.at }];
      default: {
        const _n: never = command;
        throw new DomainError("UNKNOWN_COMMAND");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "LivestockHerdRegistered":
        return { status: "active", id: event.id, species: event.species, headCount: 0 };
      case "LivestockHerdAnimalsAdded":
        if (state.status !== "active") return state;
        return { ...state, headCount: state.headCount + event.count };
      case "LivestockHerdAnimalsRemoved":
        if (state.status !== "active") return state;
