```typescript
export type FarmEvent =
  | { type: "FarmRegistered"; id: string; owner: string; hectares: number }
  | { type: "FarmCropStarted"; cropId: string }
  | { type: "FarmCropEnded"; cropId: string }
  | { type: "FarmDecommissioned"; at: string }
  | { type: "FarmOwnerChanged"; owner: string };

export interface FarmSummaryView {
  readonly id: string;
  readonly owner: string;
  readonly hectares: number;
  readonly activeCrops: number;
  readonly decommissioned: boolean;
}

export const emptyView: FarmSummaryView = {
  id: "",
  owner: "",
  hectares: 0,
  activeCrops: 0,
  decommissioned: false,
};

export function project(view: FarmSummaryView, event: FarmEvent): FarmSummaryView {
  switch (event.type) {
    case "FarmRegistered":
      return { id: event.id, owner: event.owner, hectares: event.hectares, activeCrops: 0, decommissioned: false };
    case "FarmCropStarted":
      return { ...view, activeCrops: view.activeCrops + 1 };
    case "FarmCropEnded":
      return { ...view, activeCrops: Math.max(0, view.activeCrops - 1) };
    case "FarmOwnerChanged":
      return { ...view, owner: event.owner };
    case "FarmDecommissioned":
      return { ...view, decommissioned: true };
    default: {
      const _n: never = event;
      return view;
    }
  }
}

export function buildFarmSummary(events: FarmEvent[]): FarmSummaryView {
  return events.reduce(project, emptyView);
}
