export type HarvestEvent =
  | { type: "HarvestScheduled"; cropId: string; harvestId: string }
  | { type: "HarvestStarted"; harvestId: string; at: string }
  | { type: "HarvestCompleted"; harvestId: string; cropId: string; yieldKg: number }
