      return {
        totalsByCrop: { ...view.totalsByCrop, [event.cropId]: prev + event.yieldKg },
        completed: view.completed + 1,
      };
    }
    case "HarvestScheduled":
    case "HarvestStarted":
    case "HarvestCancelled":
      return view;
    default: {
      const _n: never = event;
      return view;
    }
  }
}
