export const CURRENT_VERSION = 3;

export interface CropV1 {
  readonly id: string;
  readonly variety: string;
}
export interface CropV2 {
  readonly id: string;
  readonly variety: string;
  readonly plantedAt: string;
}
export interface CropV3 {
  readonly id: string;
  readonly variety: string;
  readonly plantedAt: string;
  readonly growthDays: number;
}

export type CropCurrent = CropV3;

export interface Snapshot<S> {
  readonly version: number;
  readonly state: S;
}

function upV1ToV2(prev: CropV1): CropV2 {
  return { ...prev, plantedAt: "1970-01-01T00:00:00.000Z" };
}

function upV2ToV3(prev: CropV2): CropV3 {
  return { ...prev, growthDays: 0 };
}

export function loadCropSnapshot(raw: Snapshot<unknown>): Snapshot<CropCurrent> {
  let version = raw.version;
  let state: unknown = raw.state;
  if (version < 1 || version > CURRENT_VERSION) {
    throw new Error(`UNSUPPORTED_SNAPSHOT_VERSION_${version}`);
  }
  if (version === 1) {
    state = upV1ToV2(state as CropV1);
    version = 2;
  }
  if (version === 2) {
