  | { type: "SoilReadingInvalidated"; fieldId: string };

export interface MoistureView {
  readonly byField: Readonly<Record<string, number>>;
}

const empty: MoistureView = { byField: {} };

export function project(view: MoistureView, event: SoilReadingEvent): MoistureView {
  switch (event.type) {
    case "SoilReadingTaken":
      return { byField: { ...view.byField, [event.fieldId]: event.moisture } };
    case "SoilReadingInvalidated": {
      const copy = { ...view.byField };
      delete copy[event.fieldId];
      return { byField: copy };
    }
    default: {
      const _n: never = event;
      return view;
    }
  }
}

export interface Batch<E> {
  readonly events: ReadonlyArray<E>;
  readonly nextRevision: bigint;
}

export interface EventSource<E> {
  readBatch(from: bigint, size: number): Promise<Batch<E>>;
}

export interface ReadStore<V> {
  persist(view: V): Promise<void>;
}

export async function rebuildMoistureView(
  source: EventSource<SoilReadingEvent>,
  store: ReadStore<MoistureView>,
  options: { from: bigint; batchSize: number }
): Promise<void> {
  let cursor = options.from;
  let view: MoistureView = empty;
  for (;;) {
    const batch = await source.readBatch(cursor, options.batchSize);
    if (batch.events.length === 0) break;
    for (const event of batch.events) {
      view = project(view, event);
    }
    await store.persist(view);
    cursor = batch.nextRevision;
  }
}
