export type FarmCommand = { type: "register"; id: string; owner: string } | { type: "decommission"; id: string; at: string };
export type FarmEvent =
  | { type: "FarmRegistered"; id: string; owner: string }
  | { type: "FarmDecommissioned"; id: string; at: string };

type WriteState = { status: "none" } | { status: "operating"; id: string; owner: string } | { status: "decommissioned"; id: string };
const initial: WriteState = { status: "none" };

function evolve(state: WriteState, event: FarmEvent): WriteState {
  switch (event.type) {
    case "FarmRegistered": return { status: "operating", id: event.id, owner: event.owner };
    case "FarmDecommissioned": if (state.status !== "operating") return state; return { status: "decommissioned", id: state.id };
    default: { const _n: never = event; return state; }
  }
}

function decide(cmd: FarmCommand, state: WriteState): FarmEvent[] {
  switch (cmd.type) {
    case "register": if (state.status !== "none") throw new Error("EXISTS"); return [{ type: "FarmRegistered", id: cmd.id, owner: cmd.owner }];
    case "decommission": if (state.status !== "operating") throw new Error("NOT_OPERATING"); return [{ type: "FarmDecommissioned", id: cmd.id, at: cmd.at }];
    default: { const _n: never = cmd; throw new Error("UNKNOWN"); }
  }
}

export interface EventStore {
  readStream(stream: string): Promise<ReadonlyArray<{ revision: bigint; event: FarmEvent }>>;
  appendToStream(stream: string, events: ReadonlyArray<FarmEvent>, opts: { expectedRevision: bigint | "no_stream" | "any" }): Promise<void>;
}

export interface FarmView { readonly id: string; readonly owner: string; readonly decommissioned: boolean; }
export interface ReadStore { getFarm(id: string): Promise<FarmView | null>; }

export async function handleCommand(cmd: FarmCommand, store: EventStore, streamOf: (id: string) => string): Promise<void> {
  const id = cmd.type === "register" ? cmd.id : cmd.id;
  const stream = streamOf(id);
  const stored = await store.readStream(stream);
  const state = stored.reduce<WriteState>((s, r) => evolve(s, r.event), initial);
  const events = decide(cmd, state);
  const expected: bigint | "no_stream" = stored.length === 0 ? "no_stream" : stored[stored.length - 1]!.revision;
  await store.appendToStream(stream, events, { expectedRevision: expected });
}

// The read store is eventually consistent with the event store.
// A subscription feeds FarmEvents into a projection that populates FarmView.
export async function queryView(id: string, reads: ReadStore): Promise<FarmView | null> {
  return reads.getFarm(id);
}
```

CQRS splits the model: the write side lives on the stream, enforces invariants via `decide`, and appends events through the event store. The read side is a projection populated by a subscription; queries never touch the write model. The two sides share the event DU but not the state type -- the write state carries invariants, while the read view carries denormalised, query-friendly fields. The read store is eventually consistent with the event store.

