export type FertiliserApplicationState =
  | { status: "none" }
  | { status: "applied"; id: string; fieldId: string; kg: number }
  | { status: "cancelled"; id: string; reason: string };

export type FertiliserApplicationCommand =
  | { type: "apply"; id: string; fieldId: string; kg: number }
  | { type: "cancel"; reason: string };

export type FertiliserApplicationEvent =
  | { type: "FertiliserApplicationApplied"; id: string; fieldId: string; kg: number }
  | { type: "FertiliserApplicationCancelled"; reason: string };

export class InvariantError extends Error {
  constructor(public readonly code: string) {
    super(code);
    this.name = "InvariantError";
  }
}

export function decide(
  command: FertiliserApplicationCommand,
  state: FertiliserApplicationState
): FertiliserApplicationEvent[] {
  switch (command.type) {
    case "apply":
      if (state.status !== "none") throw new InvariantError("ALREADY_APPLIED");
      if (command.kg <= 0) throw new InvariantError("NON_POSITIVE_KG");
      return [{ type: "FertiliserApplicationApplied", id: command.id, fieldId: command.fieldId, kg: command.kg }];
    case "cancel":
      if (state.status !== "applied") throw new InvariantError("NOT_APPLIED");
      return [{ type: "FertiliserApplicationCancelled", reason: command.reason }];
    default: {
      const _n: never = command;
      throw new InvariantError("UNKNOWN_COMMAND");
    }
  }
}
