import { Effect } from "effect";

export type WeatherEvent =
  | { type: "WeatherReported"; stationId: string; tempC: number; rainMm: number; at: string }
  | { type: "WeatherAlertRaised"; kind: "storm" | "drought" | "frost" }
  | { type: "WeatherAlertCleared" };

export interface WeatherState {
  readonly stationId: string;
  readonly tempC: number;
  readonly rainMm: number;
  readonly alert: "storm" | "drought" | "frost" | null;
  readonly lastAt: string;
}

export const emptyWeather: WeatherState = {
  stationId: "",
  tempC: 0,
  rainMm: 0,
  alert: null,
  lastAt: "1970-01-01T00:00:00.000Z",
};

export function evolve(state: WeatherState, event: WeatherEvent): WeatherState {
  switch (event.type) {
    case "WeatherReported":
      return { stationId: event.stationId, tempC: event.tempC, rainMm: event.rainMm, alert: state.alert, lastAt: event.at };
    case "WeatherAlertRaised":
      return { ...state, alert: event.kind };
    case "WeatherAlertCleared":
      return { ...state, alert: null };
    default: {
      const _n: never = event;
      return state;
    }
  }
}

export async function aggregateStream<S, E>(
  events: AsyncIterable<E>,
  step: (s: S, e: E) => S,
  initial: S
): Promise<S> {
  let acc = initial;
  for await (const event of events) {
    acc = step(acc, event);
  }
  return acc;
}

export function loadWeather(events: AsyncIterable<WeatherEvent>): Effect.Effect<WeatherState, Error> {
  return Effect.tryPromise({
    try: () => aggregateStream(events, evolve, emptyWeather),
    catch: (err) => (err instanceof Error ? err : new Error(String(err))),
  });
}
